import React, { useState } from 'react';
import TextField from '@material-ui/core/TextField';
import Button from '@material-ui/core/Button';
import { useDispatch } from 'react-redux';
import { addCategory } from '../../../actions/menu'; // Importera din Redux-action
import ScrollDialog from '../../dialog'; // Importera ScrollDialog

function AddCategory() {
  const [categoryData, setCategoryData] = useState({ categoryName: '' });
  const [openDialog, setOpenDialog] = useState(false); // State för att styra dialogens öppning
  const dispatch = useDispatch();

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setCategoryData({
      ...categoryData,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const newCategory = {
      newCategory: categoryData.categoryName,
    };
    dispatch(addCategory(newCategory));
    handleCloseDialog(); // Stäng dialogen efter att kategorin har lagts till
  };

  const handleOpenDialog = () => {
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
  };

  return (
    <div>
      {/* Knappen som öppnar dialogen */}
      <Button variant="contained" color="primary" onClick={handleOpenDialog}>
        Add new category
      </Button>
      {/* Dialogkomponenten */}
      <ScrollDialog title="Add New Category" open={openDialog} onClose={handleCloseDialog}>
        {/* Formuläret för att lägga till kategori */}
        <form onSubmit={handleSubmit}>
          <TextField
            name="categoryName"
            label="New category"
            variant="outlined"
            value={categoryData.categoryName}
            onChange={handleInputChange}
          />
          <p />
          <Button variant="contained" color="primary" type="submit">
            Add new category
          </Button>
        </form>
      </ScrollDialog>
    </div>
  );
}

export default AddCategory;
